+    *lock_mutex(&READINESS_SEMANTIC_CACHE) = (
+        Instant::now(),
+        Some(ReadinessSemanticCacheEntry {
+            database_url: config.database_url.clone(),
+            storage_root: config.storage_root.clone(),
