+        return Err(format!(
+            "sqlite schema missing required readiness tables: {}",
+            missing_tables.join(", ")
+        ));
+    }
+
+    if let Some(drift) = inspect_archive_db_drift(&config.storage_root, conn)? {
+        return Err(drift.readiness_error());
+    }
+
+    Ok(())
 }

